#include <hexi/hexi.h>
#include <cstdint>
#include <span>

struct MessageHeader {
    uint16_t message_type;
    uint32_t body_length;
    uint32_t footer;
};

MessageHeader read_header_and_skip_body(const std::span<const uint8_t> buffer) {
    std::vector<uint8_t> temp_buffer(buffer.begin(), buffer.end());
    hexi::buffer_adaptor adaptor(temp_buffer);
    hexi::binary_stream stream(adaptor);

    MessageHeader header;
    stream >> header.message_type >> header.body_length;

    stream.skip(header.body_length);

    stream >> header.footer;

    return header;
}

test cases:
#include <gtest/gtest.h>
#include <hexi/hexi.h>
#include <cstdint>
#include <span>
#include <vector>

// Include the implementation
#include "implementation.hpp"

// Helper function to create test buffer
std::vector<uint8_t> create_message_buffer(uint16_t msg_type, uint32_t body_len, const std::vector<uint8_t>& body, uint32_t footer) {
    std::vector<uint8_t> buffer;
    hexi::buffer_adaptor adaptor(buffer);
    hexi::binary_stream stream(adaptor);

    stream << msg_type << body_len;
    stream.put(body.data(), body.size());
    stream << footer;

    return buffer;
}

TEST(MessageHeader, ReadAndSkip) {
    std::vector<uint8_t> body = {1, 2, 3, 4, 5, 6, 7, 8};
    auto buffer = create_message_buffer(100, body.size(), body, 9999);

    MessageHeader header = read_header_and_skip_body(buffer);

    EXPECT_EQ(100, header.message_type);
    EXPECT_EQ(body.size(), header.body_length);
    EXPECT_EQ(9999, header.footer);
}

TEST(MessageHeader, SkipLargeBody) {
    std::vector<uint8_t> body(1000, 0xFF);
    auto buffer = create_message_buffer(300, body.size(), body, 5678);

    MessageHeader header = read_header_and_skip_body(buffer);

    EXPECT_EQ(300, header.message_type);
    EXPECT_EQ(1000, header.body_length);
    EXPECT_EQ(5678, header.footer);
}

