Looking at the Hexi library usage patterns, here's the complete implementation using zero-copy operations:

```cpp
#include <hexi/hexi.h>
#include <cstdint>
#include <span>
#include <string_view>

struct PacketHeader {
    uint8_t version;
    uint8_t flags;
    uint16_t packet_id;
};

PacketHeader read_packet_header(const std::span<const uint8_t> buffer) {
    // Create a buffer adaptor from the input span
    hexi::buffer_adaptor adaptor(buffer);

    // Create a binary stream for reading
    hexi::binary_stream stream(adaptor);

    // Read the header fields using zero-copy operations
    uint8_t version = stream.get<uint8_t>();
    uint8_t flags = stream.get<uint8_t>();
    uint16_t packet_id = stream.get<uint16_t>();

    return PacketHeader{version, flags, packet_id};
}

std::string_view read_message_until_delimiter(const std::span<const uint8_t> buffer) {
    // Create a buffer adaptor from the input span
    hexi::buffer_adaptor adaptor(buffer);

    // Create a binary stream for reading
    hexi::binary_stream stream(adaptor);

    // Use view() to get a zero-copy view of the null-terminated string
    // The view method reads until the specified delimiter (null terminator)
    auto string_span = stream.view('\0');

    // Convert the span of bytes to a string_view
    return std::string_view(
        reinterpret_cast<const char*>(string_span.data()), 
        string_span.size()
    );
}
```

