```cpp
#include <hexi/hexi.h>
#include <vector>
#include <cstdint>
#include <span>

struct DataResult {
    uint8_t data_type;
    std::vector<uint32_t> int_items;
    std::vector<float> float_items;
};

DataResult preview_and_read_data(const std::span<const uint8_t> buffer) {
    DataResult result;

    // Create buffer adaptor and binary stream
    hexi::buffer_adaptor adaptor(buffer);
    hexi::binary_stream stream(adaptor);

    // Preview the first byte (data_type) without advancing the read pointer
    // Use peek to read without consuming
    result.data_type = stream.peek<uint8_t>();

    // Check if we have enough data for at least the header
    if (buffer.size() < (sizeof(uint8_t) + sizeof(uint32_t))) {
        // Not enough data for header, return empty result
        return result;
    }

    // Now read the actual data_type (this will advance the pointer)
    result.data_type = stream.get<uint8_t>();

    // Read the item count
    uint32_t item_count = stream.get<uint32_t>();

    // Calculate required size based on data type
    size_t item_size = (result.data_type == 0) ? sizeof(uint32_t) : sizeof(float);
    size_t required_size = sizeof(uint8_t) + sizeof(uint32_t) + (item_count * item_size);

    // Check if we have enough data for all items
    if (buffer.size() < required_size) {
        // Not enough data, return what we have (header is already read)
        return result;
    }

    // Read items based on data type
    if (result.data_type == 0) {
        // Integer items
        result.int_items.reserve(item_count);
        for (uint32_t i = 0; i < item_count; ++i) {
            result.int_items.push_back(stream.get<uint32_t>());
        }
    } else if (result.data_type == 1) {
        // Float items
        result.float_items.reserve(item_count);
        for (uint32_t i = 0; i < item_count; ++i) {
            result.float_items.push_back(stream.get<float>());
        }
    }
    // If data_type is neither 0 nor 1, we simply return empty vectors

    return result;
}
