#include <hexi/hexi.h>
#include <cstdint>
#include <span>

struct PacketHeader {
    uint32_t magic;
    uint16_t version;
    uint16_t flags;
};

PacketHeader read_header_with_span(const std::span<const uint8_t> buffer) {
    // Create buffer adaptor from the span
    hexi::buffer_adaptor adaptor(buffer);

    // Create binary stream from the adaptor
    hexi::binary_stream stream(adaptor);

    // Check if there's enough data available for the header
    if (adaptor.available_read() < sizeof(PacketHeader)) {
        throw std::runtime_error("Not enough data to read header");
    }

    // Get the read pointer for zero-copy operations
    const uint8_t* read_ptr = adaptor.read_pointer();

    // Use binary_stream's zero-copy operations to read the header
    PacketHeader header;
    header.magic = stream.get<uint32_t>();
    header.version = stream.get<uint16_t>();
    header.flags = stream.get<uint16_t>();

    return header;
}
```

