#include <hexi/hexi.h>
#include <vector>
#include <cstdint>
#include <string>

struct UserData {
    uint32_t user_id;
    std::string name;

    void serialise(auto& adaptor) const {
        adaptor(user_id, name);
    }
};

std::vector<uint8_t> write_and_serialise_packet(uint32_t header, const UserData& data) {
    std::vector<uint8_t> buffer;
    hexi::buffer_adaptor adaptor(buffer, hexi::init_empty);

    // Write header using buffer_adaptor's write()
    adaptor.write(&header, sizeof(uint32_t));

    // Serialize data using binary_stream's serialise()
    hexi::binary_stream stream(adaptor);
    stream.serialise(data);

    return buffer;
}

