Looking at the code fragments, I can see that `hexi::dynamic_buffer` is a circular buffer implementation. To peek at data without advancing the read pointer, we need to:

1. Check how many bytes are available to read
2. Handle the case where the data wraps around the circular buffer
3. Copy the data without modifying the read position

Here's the complete implementation:

```cpp
#include <hexi/dynamic_buffer.h>
#include <vector>
#include <cstdint>
#include <algorithm>

template<size_t block_size = 1024>
std::vector<uint8_t> peek_data_from_buffer(const hexi::dynamic_buffer<block_size>& buffer, size_t bytes_to_peek) {
    // Get the number of bytes available to read
    size_t available_bytes = buffer.size();

    // If we try to peek more than available, adjust to available bytes
    bytes_to_peek = std::min(bytes_to_peek, available_bytes);

    // Create result vector
    std::vector<uint8_t> result;
    result.reserve(bytes_to_peek);

    // Get current read position
    size_t read_pos = buffer.tell_read();
    size_t buffer_size = buffer.capacity();

    // Calculate how many bytes we can read before wrapping
    size_t bytes_until_wrap = buffer_size - read_pos;

    if (bytes_to_peek <= bytes_until_wrap) {
        // Simple case: no wrap-around needed
        for (size_t i = 0; i < bytes_to_peek; ++i) {
            result.push_back(static_cast<uint8_t>(buffer[read_pos + i]));
        }
    } else {
        // Wrap-around case: read from current position to end, then from beginning
        // First part: from current read position to end of buffer
        for (size_t i = 0; i < bytes_until_wrap; ++i) {
            result.push_back(static_cast<uint8_t>(buffer[read_pos + i]));
        }

        // Second part: from beginning of buffer
        size_t remaining_bytes = bytes_to_peek - bytes_until_wrap;
        for (size_t i = 0; i < remaining_bytes; ++i) {
            result.push_back(static_cast<uint8_t>(buffer[i]));
        }
    }

    return result;
}
