```cpp
#include <hexi/static_buffer.h>
#include <cstdint>

template<size_t buffer_size = 1024>
void write_uint32_to_buffer(hexi::static_buffer<std::byte, buffer_size>& buffer, uint32_t value) {
    // Convert the uint32_t to bytes in big-endian order
    std::byte bytes[4];
    bytes[0] = static_cast<std::byte>((value >> 24) & 0xFF);
    bytes[1] = static_cast<std::byte>((value >> 16) & 0xFF);
    bytes[2] = static_cast<std::byte>((value >> 8) & 0xFF);
    bytes[3] = static_cast<std::byte>(value & 0xFF);

    // Write the bytes to the buffer
    buffer.write(bytes, 4);
}

template<size_t buffer_size = 1024>
uint32_t read_uint32_from_buffer(hexi::static_buffer<std::byte, buffer_size>& buffer) {
    // Read 4 bytes from the buffer
    std::byte bytes[4];
    buffer.read(bytes, 4);

    // Convert bytes back to uint32_t in big-endian order
    uint32_t value = (static_cast<uint32_t>(bytes[0]) << 24) |
                     (static_cast<uint32_t>(bytes[1]) << 16) |
                     (static_cast<uint32_t>(bytes[2]) << 8) |
                     static_cast<uint32_t>(bytes[3]);

    return value;
}
```

