#include <gtest/gtest.h>
#include <hexi/pmc/buffer_adaptor.h>
#include <vector>
#include <cstdint>
#include <cstring>

// Include the implementation
#include "implementation.hpp"

TEST(BufferAdaptor, PeekData) {
    std::vector<std::byte> storage(1000);
    hexi::pmc::buffer_adaptor<std::vector<std::byte>> adaptor(storage, hexi::init_empty);

    uint32_t value = 12345;
    adaptor.write(&value, sizeof(value));

    uint32_t peeked = 0;
    peek_value_from_buffer(adaptor, peeked);

    EXPECT_EQ(value, peeked);

    // Read pointer should not advance, so we can read again
    uint32_t read_value = 0;
    adaptor.read(&read_value, sizeof(read_value));
    EXPECT_EQ(value, read_value);
}

TEST(BufferAdaptor, PeekAndCompare) {
    std::vector<std::byte> storage(1000);
    hexi::pmc::buffer_adaptor<std::vector<std::byte>> adaptor(storage, hexi::init_empty);

    uint8_t data[] = {1, 2, 3, 4, 5};
    adaptor.write(data, sizeof(data));

    uint8_t expected[] = {1, 2, 3, 4, 5};
    EXPECT_TRUE(peek_and_compare(adaptor, expected, sizeof(expected)));

    // Data should still be readable
    uint8_t read_data[5] = {0};
    adaptor.read(read_data, sizeof(read_data));
    EXPECT_EQ(0, std::memcmp(data, read_data, sizeof(data)));
}

TEST(BufferAdaptor, PeekMultipleTimes) {
    std::vector<std::byte> storage(1000);
    hexi::pmc::buffer_adaptor<std::vector<std::byte>> adaptor(storage, hexi::init_empty);

    uint32_t value = 999;
    adaptor.write(&value, sizeof(value));

    uint32_t peek1 = 0, peek2 = 0;
    peek_value_from_buffer(adaptor, peek1);
    peek_value_from_buffer(adaptor, peek2);

    EXPECT_EQ(value, peek1);
    EXPECT_EQ(value, peek2);
    EXPECT_EQ(peek1, peek2);

    // Verify data can still be read
    uint32_t read_value = 0;
    adaptor.read(&read_value, sizeof(read_value));
    EXPECT_EQ(value, read_value);
}

TEST(BufferAdaptor, PeekAfterPartialRead) {
    std::vector<std::byte> storage(1000);
    hexi::pmc::buffer_adaptor<std::vector<std::byte>> adaptor(storage, hexi::init_empty);

    uint8_t data[] = {1, 2, 3, 4, 5, 6, 7, 8};
    adaptor.write(data, sizeof(data));

    // Read first 3 bytes
    uint8_t first_read[3] = {0};
    adaptor.read(first_read, sizeof(first_read));
    EXPECT_EQ(0, std::memcmp(data, first_read, sizeof(first_read)));

    // Now peek at next 3 bytes (should be bytes 3-5)
    uint8_t peeked[3] = {0};
    peek_data_from_buffer(adaptor, peeked, sizeof(peeked));
    EXPECT_EQ(0, std::memcmp(data + 3, peeked, sizeof(peeked)));

    // Peek again to verify read pointer hasn't moved
    uint8_t peeked_again[3] = {0};
    peek_data_from_buffer(adaptor, peeked_again, sizeof(peeked_again));
    EXPECT_EQ(0, std::memcmp(peeked, peeked_again, sizeof(peeked_again)));
}

