    // Read the message_type (uint16_t)
    header.message_type = buffer.read<uint16_t>();

    // Read the body_length (uint32_t)
    header.body_length = buffer.read<uint32_t>();

    // Skip the body data based on the length field
    skip_bytes_in_buffer(buffer, header.body_length);

    return header;
}
```

