// Include the implementation
#include "implementation.hpp"

TEST(BufferAdaptor, CheckCanWriteSeek) {
    std::vector<std::byte> storage(1000);
    hexi::pmc::buffer_adaptor adaptor(storage, hexi::init_empty);

    EXPECT_TRUE(check_can_write_seek(adaptor));
}

TEST(BufferAdaptor, SeekWritePosition) {
    std::vector<std::byte> storage(1000);
    hexi::pmc::buffer_adaptor adaptor(storage, hexi::init_empty);

    uint32_t value1 = 100;
    adaptor.write(&value1, sizeof(value1));

    // Seek backward
    seek_write_position(adaptor, hexi::buffer_seek::sk_backward, sizeof(value1));

    uint32_t value2 = 200;
    adaptor.write(&value2, sizeof(value2));

    adaptor.clear();

    uint32_t read_value = 0;
    adaptor.read(&read_value, sizeof(read_value));

    EXPECT_EQ(value2, read_value);
}

TEST(BufferAdaptor, UpdateHeaderAtPosition) {
    std::vector<std::byte> storage(1000);
    hexi::pmc::buffer_adaptor adaptor(storage, hexi::init_empty);

    uint32_t header_value = 12345;
    update_header_at_position(adaptor, header_value);

    adaptor.clear();

    uint32_t read_header = 0;
    adaptor.read(&read_header, sizeof(read_header));

    EXPECT_EQ(header_value, read_header);

    uint32_t read_body = 0;
    adaptor.read(&read_body, sizeof(read_body));

    EXPECT_EQ(999, read_body);
}

TEST(BufferAdaptor, SeekAbsolute) {
    std::vector<std::byte> storage(1000);
    hexi::pmc::buffer_adaptor adaptor(storage, hexi::init_empty);

    uint32_t values[] = {10, 20, 30};
    adaptor.write(values, sizeof(values));

    // Seek to position 4 (after first value)
    seek_write_position(adaptor, hexi::buffer_seek::sk_absolute, sizeof(uint32_t));

    uint32_t new_value = 99;
    adaptor.write(&new_value, sizeof(new_value));

    adaptor.clear();

    uint32_t read_values[3] = {0};
    adaptor.read(read_values, sizeof(read_values));

    EXPECT_EQ(10, read_values[0]);
    EXPECT_EQ(99, read_values[1]);
    EXPECT_EQ(30, read_values[2]);
}

