Looking at the Hexi library code fragments, I can implement the varint encoding and decoding functions. Here's the complete implementation:

```cpp
#include <hexi/shared.h>
#include <hexi/pmc/buffer_adaptor.h>
#include <hexi/pmc/binary_stream_writer.h>
#include <hexi/pmc/binary_stream_reader.h>
#include <vector>
#include <cstdint>

using namespace hexi::detail;

template<typename T>
std::size_t encode_varint(hexi::pmc::binary_stream_writer& writer, T value) {
    std::size_t bytes_written = 0;

    // Handle negative values using zigzag encoding
    typename std::make_unsigned<T>::type unsigned_value;
    if constexpr (std::is_signed<T>::value) {
        // Zigzag encoding for signed integers
        unsigned_value = (value << 1) ^ (value >> (sizeof(T) * 8 - 1));
    } else {
        unsigned_value = value;
    }

    // Encode the unsigned value as varint
    do {
        uint8_t byte = unsigned_value & 0x7F;
        unsigned_value >>= 7;

        if (unsigned_value != 0) {
            byte |= 0x80; // Set continuation bit
        }

        writer.write(&byte, 1);
        bytes_written++;

        if (writer.state() != stream_state::ok) {
            break;
        }
    } while (unsigned_value != 0);

    return bytes_written;
}

template<typename T>
T decode_varint(hexi::pmc::binary_stream_reader& reader) {
    T result = 0;
    int shift = 0;
    uint8_t byte;

    do {
        reader.read(&byte, 1);

        if (reader.state() != stream_state::ok) {
            break;
        }

        result |= static_cast<T>(byte & 0x7F) << shift;
        shift += 7;

        // Check if we're reading beyond the type's capacity
        if (shift >= static_cast<int>(sizeof(T) * 8)) {
            // This is an error condition - varint is too large for the target type
            break;
        }

    } while (byte & 0x80); // Continue if continuation bit is set

    // Handle zigzag decoding for signed integers
    if constexpr (std::is_signed<T>::value) {
        if ((result & 1) == 0) {
            result = result >> 1; // Positive number
        } else {
            result = ~(result >> 1); // Negative number
        }
    }

    return result;
}

template<typename T>
bool encode_decode_roundtrip(T original_value) {
    // Create a buffer to hold the encoded data
    std::vector<uint8_t> buffer;
    hexi::pmc::buffer_adaptor adaptor(buffer);

    // Encode the value
    hexi::pmc::binary_stream_writer writer(adaptor);
    encode_varint<T>(writer, original_value);

    if (writer.state() != stream_state::ok) {
        return false;
    }

    // Create a new adaptor for reading from the same buffer
    hexi::pmc::buffer_adaptor read_adaptor(buffer);
    hexi::pmc::binary_stream_reader reader(read_adaptor);

    // Decode the value
    T decoded_value = decode_varint<T>(reader);

    if (reader.state() != stream_state::ok) {
        return false;
    }

    // Compare with original
    return original_value == decoded_value;
}
```

