#include <hexi/hexi.h>
#include <string>
#include <string_view>

template<typename buf_type, typename exceptions, typename endianness>
void write_string_prefixed_varint(hexi::binary_stream<buf_type, exceptions, endianness>& stream, const std::string& str) {
    stream << hexi::prefixed_varint(str);
}

template<typename buf_type, typename exceptions, typename endianness>
std::string read_string_prefixed_varint(hexi::binary_stream<buf_type, exceptions, endianness>& stream) {
    std::string result;
    stream >> hexi::prefixed_varint(result);
    return result;
}

