#include <hexi/shared.h>
#include <array>
#include <cstdint>
#include <algorithm>

using namespace hexi::detail;

template<std::size_t Size>
constexpr auto create_filled_array(std::uint8_t value) {
    // Create an array and fill it with the specified value
    std::array<std::uint8_t, Size> arr{};

    // Fill the array with the specified value at compile time
    for (std::size_t i = 0; i < Size; ++i) {
        arr[i] = value;
    }

    return arr;
}

bool verify_filled_array(const auto& arr, std::uint8_t expected_value) {
    // Verify all elements equal expected_value
    for (const auto& element : arr) {
        if (element != expected_value) {
            return false;
        }
    }
    return true;
}
```

Alternative implementation using more modern C++ features:

