        // Extract information from the buffer_underrun exception
        return UnderrunInfo{ex.read_size, ex.total_read, ex.buff_size, true};
    } catch (...) {
        // If it's not a buffer_underrun exception, return default values
        return UnderrunInfo{0, 0, 0, false};
    }
}

