        // If successful, return with occurred = false
        return UnderrunInfo{0, 0, 0, false};
    } catch (const hexi::buffer_underrun& ex) {
        // Catch buffer_underrun and extract information
        return UnderrunInfo{ex.read_size, ex.total_read, ex.buff_size, true};
    }
