#include <hexi/hexi.h>
#include <string>
#include <cstdint>

struct PaddedData {
    uint16_t header;
    std::string data;
    uint32_t footer;
};

std::vector<uint8_t> serialize_with_padding(const PaddedData& packet) {
    std::vector<uint8_t> buffer;
    hexi::buffer_adaptor adaptor(buffer);
    hexi::binary_stream stream(adaptor);

    stream << packet.header;
    stream << packet.data;
    stream.fill<16>(0x00);
    stream << packet.footer;

    return buffer;
}

test cases:
#include <gtest/gtest.h>
#include <hexi/hexi.h>
#include <string>
#include <cstdint>
#include <vector>

// Include the implementation
#include "implementation.hpp"

TEST(PaddedData, SerializeWithPadding) {
    PaddedData packet;
    packet.header = 0x1234;
    packet.data = "test";
    packet.footer = 0x567890AB;

    auto buffer = serialize_with_padding(packet);

    // Verify buffer size: header(2) + data_prefix(4) + data(4) + padding(16) + footer(4) = 30
    EXPECT_GE(buffer.size(), 30);

    // Verify padding bytes are 0x00
    size_t padding_start = 2 + 4 + 4; // header + prefix + data
    for (size_t i = 0; i < 16; ++i) {
        EXPECT_EQ(0x00, buffer[padding_start + i]) << "Padding byte at index " << i << " should be 0x00";
    }
}

TEST(PaddedData, PaddingCorrectSize) {
    PaddedData packet;
    packet.header = 0xABCD;
    packet.data = "short";
    packet.footer = 0x12345678;

    auto buffer = serialize_with_padding(packet);

    // Calculate expected size
    size_t expected_size = sizeof(uint16_t) + sizeof(uint32_t) + packet.data.size() + 16 + sizeof(uint32_t);
    EXPECT_EQ(expected_size, buffer.size());
}

TEST(PaddedData, RoundTrip) {
    PaddedData original;
    original.header = 0x1111;
    original.data = "round trip test";
    original.footer = 0x22222222;

    auto buffer = serialize_with_padding(original);

    // Deserialize manually to verify
    std::vector<uint8_t> temp_buffer(buffer.begin(), buffer.end());
    hexi::buffer_adaptor adaptor(temp_buffer);
    hexi::binary_stream stream(adaptor);

    PaddedData deserialized;
    stream >> deserialized.header >> deserialized.data;
    stream.skip(16); // skip padding
    stream >> deserialized.footer;

    EXPECT_EQ(original.header, deserialized.header);
    EXPECT_EQ(original.data, deserialized.data);
    EXPECT_EQ(original.footer, deserialized.footer);
}

