struct ProtocolPacket {
    uint32_t message_id;
    std::vector<uint16_t> data_values;
    uint32_t checksum;
};

std::vector<uint8_t> serialize_protocol_packet(const ProtocolPacket& packet) {
    std::vector<uint8_t> buffer;
    hexi::buffer_adaptor adaptor(buffer);
    hexi::binary_stream stream(adaptor);

    // Convert and write message_id
    uint32_t big_message_id = hexi::endian::native_to_big(packet.message_id);
    stream.write(big_message_id);

    // Convert and write data_values vector
    std::vector<uint16_t> big_data_values;
    big_data_values.reserve(packet.data_values.size());
    for (auto value : packet.data_values) {
        big_data_values.push_back(hexi::endian::native_to_big(value));
    }
    stream.write_container(big_data_values);

    // Convert and write checksum
    uint32_t big_checksum = hexi::endian::native_to_big(packet.checksum);
    stream.write(big_checksum);

    return buffer;
}

ProtocolPacket deserialize_protocol_packet(const std::span<const uint8_t> buffer) {
    ProtocolPacket packet;
    hexi::buffer_adaptor adaptor(buffer);
    hexi::binary_stream stream(adaptor);

    // Read and convert message_id
    uint32_t big_message_id;
    stream.read(big_message_id);
    packet.message_id = hexi::endian::big_to_native(big_message_id);

    // Read count and convert
    uint32_t count;
    stream.read(count);
    count = hexi::endian::big_to_native(count);

    // Read and convert data_values
    std::vector<uint16_t> big_data_values;
    stream.read_container(big_data_values, count);

    packet.data_values.reserve(big_data_values.size());
    for (auto value : big_data_values) {
        packet.data_values.push_back(hexi::endian::big_to_native(value));
    }

    // Read and convert checksum
    uint32_t big_checksum;
    stream.read(big_checksum);
    packet.checksum = hexi::endian::big_to_native(big_checksum);

    return packet;
}

struct ProtocolHeader {
    uint32_t message_id;
};

ProtocolHeader extract_protocol_header(const std::span<const uint8_t> buffer) {
    ProtocolHeader header;
    hexi::buffer_adaptor adaptor(buffer);
    hexi::binary_stream stream(adaptor);

    // Use span to get zero-copy view of first 4 bytes
    auto message_id_span = stream.span<uint32_t>(1);
    if (!message_id_span.empty()) {
        uint32_t big_message_id;
        std::memcpy(&big_message_id, message_id_span.data(), sizeof(uint32_t));
        header.message_id = hexi::endian::big_to_native(big_message_id);

        // Skip past the header
        stream.skip(sizeof(uint32_t));
    }

    return header;
}
